import React, { useState } from 'react';
import { Link, Navigate, useNavigate } from 'react-router-dom';
import { useAppContext } from '../context/AppContext';

export default function Login() {
  const navigate = useNavigate();
  const { login, session } = useAppContext();
  const [identifier, setIdentifier] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  if (session) {
    return <Navigate to="/dashboard" replace />;
  }

  const handleSubmit = (event) => {
    event.preventDefault();
    const result = login({ identifier, password });

    if (result.error) {
      setError(result.error);
      return;
    }

    navigate('/dashboard');
  };

  return (
    <div className="auth-page">
      <div className="auth-panel">
        <h1>Welcome back</h1>
        <p>Sign in to access your breed classification dashboard.</p>

        <form onSubmit={handleSubmit} className="auth-form">
          <label>
            Username or email
            <input value={identifier} onChange={(event) => setIdentifier(event.target.value)} placeholder="Enter username or email" />
          </label>
          <label>
            Password
            <input type="password" value={password} onChange={(event) => setPassword(event.target.value)} placeholder="Enter password" />
          </label>

          {error && <div className="field-error">{error}</div>}

          <button type="submit" className="primary-button">Sign in</button>
        </form>

        <p className="auth-footnote">
          New to the dashboard? <Link to="/signup">Create an account</Link>
        </p>
      </div>
    </div>
  );
}
